"use strict";parserFactory.register("amor-yaoi.com",()=>new AmoryaoiParser);class AmoryaoiParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("#content a")].filter(e=>e.href.includes("&chapter=")).map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("#content")}extractTitleImpl(e){return e.querySelector("h1")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"#jumpmenu, #pagelinks, #reviewform, #sort"),super.removeUnwantedElementsFromContentElement(e)}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("#output, blockquote")]}}